import styled from "styled-components"
import Brand from '../LandingPage/Brand'

const Footer = () => {
  return (
    <FooterContainer>
      <FooterBrand />
      <div style={{ display: "flex", columnGap: "5em", justifyContent: "center" }}>
        <List>
          <ListHeader> Quick Links </ListHeader>
          <li> Home </li>
          <li> Projects </li>
        </List>
        <List>
          <ListHeader> Contact </ListHeader>
          <li> Email@Email.com </li>
          <li> Github </li>
        </List>
      </div>
      <Copyright> © 2021 Adam Jałocha </Copyright>
    </FooterContainer>
  )
}

const FooterContainer = styled.footer`
  color: white;

  display: grid;
  grid-template-columns: auto 1fr;
  grid-template-rows: 1fr auto;
  row-gap: 2em;
  padding-top: 2em;

  align-items: center;
  justify-content: center;
`

const FooterBrand = styled(Brand)`
  font-size: 1.3em;
  padding: 0 3em;
  width: auto;
`

const Copyright = styled.span`
  grid-row: 2;
  grid-column: 1/3;
  text-align: center;
  padding: 1em 0;
  width: 100%;
  border-top: 1em solid red;
`

const List = styled.ul`
  display: flex;
  flex-direction: column;
  row-gap: 0.5em;
`

const ListHeader = styled.li`
  font-weight: 500;
  margin-bottom: 0.5em;
`


export default Footer
